INSERT INTO article (id, category_id, title, summary, content, author, view_count, collect_count, status, publish_time, created_at, updated_at, deleted) VALUES
(101, 1, '如何应对考试焦虑', '考试焦虑是学生常见的心理问题，本文介绍几种有效的应对方法。', '<h2>什么是考试焦虑？</h2><p>考试焦虑是指在考试前或考试过程中出现的紧张、担心、恐惧等负面情绪。</p>', '心理健康中心', 156, 23, 1, NOW(), NOW(), NOW(), 0),
(102, 1, '深呼吸放松法', '深呼吸是最简单有效的放松方法之一。', '<h2>深呼吸的好处</h2><p>深呼吸可以帮助我们快速平静下来，缓解焦虑。</p>', '李心理师', 234, 45, 1, NOW(), NOW(), NOW(), 0),
(103, 2, '认识抑郁情绪', '抑郁情绪不等于抑郁症，了解两者的区别很重要。', '<h2>抑郁情绪的特点</h2><p>抑郁情绪是一种正常的情绪反应。</p>', '王医生', 189, 34, 1, NOW(), NOW(), NOW(), 0),
(104, 2, '走出情绪低谷的5个方法', '当你感到情绪低落时，这些方法可以帮助你。', '<h2>1. 运动起来</h2><p>运动可以促进大脑分泌内啡肽，改善情绪。</p>', '张咨询师', 267, 52, 1, NOW(), NOW(), NOW(), 0),
(105, 3, '大学生人际交往技巧', '良好的人际关系对大学生活至关重要。', '<h2>建立良好人际关系的重要性</h2><p>大学是培养社交能力的重要时期。</p>', '刘老师', 312, 67, 1, NOW(), NOW(), NOW(), 0),
(106, 3, '如何处理室友矛盾', '宿舍是大学生活的重要场所，学会处理室友关系很重要。', '<h2>常见矛盾类型</h2><p>作息时间不同、生活习惯差异等。</p>', '陈心理师', 198, 41, 1, NOW(), NOW(), NOW(), 0),
(107, 4, '时间管理与学业压力', '合理的时间管理可以有效缓解学业压力。', '<h2>时间管理的重要性</h2><p>良好的时间管理能帮助我们更高效地完成学习任务。</p>', '赵教授', 245, 58, 1, NOW(), NOW(), NOW(), 0),
(108, 4, '克服拖延症的有效方法', '拖延症是很多学生面临的问题。', '<h2>拖延的原因</h2><p>完美主义、害怕失败、任务太大等。</p>', '孙老师', 289, 63, 1, NOW(), NOW(), NOW(), 0),
(109, 1, '情绪管理的艺术', '学会管理情绪，让生活更加从容。', '<h2>认识情绪</h2><p>情绪是人类的正常反应，没有好坏之分。</p>', '周心理师', 276, 71, 1, NOW(), NOW(), NOW(), 0),
(110, 3, '培养自信心的方法', '自信是成功的基石。', '<h2>自信的来源</h2><p>自信来自于对自己能力的认可。</p>', '吴老师', 321, 79, 1, NOW(), NOW(), NOW(), 0),
(111, 2, '什么是心理咨询', '心理咨询不是看病，而是一种专业的心理帮助。', '<h2>心理咨询的定义</h2><p>心理咨询是由专业心理咨询师通过对话帮助来访者解决心理困扰的过程。</p>', '郑医生', 198, 45, 1, NOW(), NOW(), NOW(), 0),
(112, 1, '正念冥想入门指南', '正念冥想是一种有效的减压方法。', '<h2>什么是正念</h2><p>正念是一种有意识地、不加评判地关注当下的状态。</p>', '马心理师', 342, 88, 1, NOW(), NOW(), NOW(), 0);
